#include <iostream>
#include <string_view>

class Base
{
public:
    std::string_view earlyBound() const
    {
        return "Base";
    }

    virtual std::string_view lateBound() const
    {
        return "Base";
    }
};

class Derived : public Base
{
public:
    std::string_view earlyBound() const
    {
        return "Derived";
    }

    std::string_view lateBound() const override
    {
        return "Derived";
    }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i)
    {
        Derived d{};
        const Base& ref{d};
        std::cout << "Early: " << ref.earlyBound() << '\n';
        std::cout << "Late: " << ref.lateBound() << '\n';
    }

    std::cout << "Done\n";

    return 0;
}

