exercises.solution_code:
#include <iostream>
#include <string>
#include <string_view>
#include <vector>

class Instrument
{
public:
    virtual ~Instrument() = default;
    std::string_view bindingType() const { return "static"; }
    virtual std::string_view play() const { return "..."; }
};

class Piano : public Instrument
{
public:
    std::string_view bindingType() const { return "dynamic"; }
    std::string_view play() const override { return "Plink"; }
};

class Drum : public Instrument
{
public:
    std::string_view bindingType() const { return "dynamic"; }
    std::string_view play() const override { return "Boom"; }
};

int main()
{
    int n{};
    std::cin >> n;
    std::vector<Instrument*> instruments{};

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "piano")
            instruments.push_back(new Piano{});
        else
            instruments.push_back(new Drum{});
    }

    for (const auto* inst : instruments)
    {
        std::cout << "Binding: " << inst->bindingType() << '\n';
        std::cout << "Sound: " << inst->play() << '\n';
    }

    std::cout << "Total: " << n << '\n';

    for (auto* inst : instruments)
        delete inst;

    return 0;
}
